namespace MunchkinLib.Models
{
    public class BaseCardsDescriptions
    {
        #region Doors
        
        //Fractions
        public static string PathfinderDescription = "Znawca Sekretów: Zanim otworzysz Drzwi, możesz obejrzeć dwie wierzchnie karty z talii Drzwi. Jedną odrzuć, a drugą połóż z powrotem na szczycie talii, potem normalnie Otwórz Drzwi.";
        public static string EagleKnightDescription = "Utrzymaj Pozycję: Podczas walki możesz odrzucić to trzech kart z ręki. Każda z nich zapewnia ci bonus +2, ale daje karę -1 do ucieczki.";
        public static string HellKnightDescription = "Zbroja Piekielnego Rycerza: Nosisz Zbroje Piekielnego Rycerza (zajmuje ona miejsce na Zbroję i Hełm), która zapewnia bonus +5 w walce. Nie możesz stracić tej zbroi tak długo, jak jesteś Piekielnym Rycerzem. Nie możesz też nosić innej Zbroi ani Hełmu, nawet jeśli ich karty na to pozwalają. Jedynym wyjątkiem jest użycie karty Kanciarz!";
        public static string DeadlyRedMantisDescription = "Skradanie się: +1 do Ucieczki. \nMorderca Do Wynajęcia: Kiedy Szukasz Guza, możesz odrzucić do trzech kart z ręki. Każda z nich zapewnia ci bonus +2 w tej walce.";

        //Races
        public static string HalflingDescription = "Raz w trakcie swojej tory mozesz sprzedać jeden Przedmiot za podwójną cenę (pozostałe Przedmioty są warte tyle, co zwykle). \n\nJeśli nie ida ci się przewszy rzut na Ucieczkę, możesz odrzucić kartę i spróbować raz jeszcze";
        public static string ElfDescription = "Zyskujesz 1 Poziom za każdego Potwora pokonanego w walce, w której pomagałeś.";
        public static string DwarfDescription = "Możesz nieść dowolną liczbę Dużych Przedmiotów. Możesz mieć 6 kart na ręce.";

        //Classes
        public static string WarriorDescription = "Szał bojowy: Możesz odrzucić do 3 kart w trakcie walki. Każda z nich daje ci bonus +1. Wygrywasz, jeśli walka konczyłaby się remisem.";
        public static string WizardDescription = "Czar Lot: Możesz odrzucić do 3 kart przy próbie Ucieczki. Każda z nich daje ci +1 do rzutu kostką. \nCzar Zauroczenie: Odrzuć całą rękę (co najmniej 3 karty), żeby zauroczyć jednego Potwora, zamiast z nim walczyć. Za tak pokonanego Potwora nie zyskujesz Poziomu, ale zbobywasz jego Skarb. Jeśli w walce uczystnieczy więcej Potworów, z pozostałymi walczysz normalnie.";
        public static string PriestDescription = "Wskrzeszenie: Raz w trakcie tury, zamiast dobierać karty odkryte, możesz wziąć część albo wszystkie z nich w wierzchu odpowiednioego stostu kart odrzuconych. Gdy to zrobisz, musisz odrzucić jedną kartę z ręki, za każdą kartę dobraną w ten sposób. \nOdpędzenie Nieumarłych: Możesz odrzucić do 3 kart w trakcie walki z nieumarłymi. Każda z nich daje ci Bunous +3.";
        public static string ThiefDescription = "Zdrada: Możesz odrzucić kartę, aby wbić nóż w plecy innego gracza (ma -2 na czas trawania walki). Ten sam gracz nie może paść twoją ofiarą dwukrotnie w jednej walce, ale jeśli walczących jest dwóch, to możesz zdradzić każdego z nich. \nKradzież: Możesz odrzucić kartę, aby sprobować ukraść nie-Duży Przedmiot innemu graczowi. Rzuć kostką: wynik 4 lub wiecej to skukces. Porażka oznacza, że zostałeś przłapany i tracisz 1 Poziom.";
        #endregion

        #region Treasures



        #endregion
    }
}
